class Solution {
    public String minWindow(String s, String t) {
        int m = s.length();
        int n = t.length();

        int[][] count = new int[n + 1][m + 1];

        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                count[i][j] = 0;
            }
        }

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (s.charAt(j) == t.charAt(i)) {
                    count[i][j]++;
                }
            }
        }

        int left = 0;
        int right = 0;
        String result = "";

        while (right < m) {
            if (count[left][right] == 0) {
                left++;
            } else if (count[left][right] > 0) {
                result += s.charAt(left);
                count[left][right]--;
                right++;
            }
        }

        return result;
    }
}
